// src/types/index.ts

export type PaymentMethod = 'paybox' | 'cash' | 'transfer' | '';
export type EventCategory = 'מתנות' | 'פעילות' | 'חג' | 'ארוע' | 'שונות';
export type CashType = 'income' | 'expense';

export interface Student {
  id: number;
  name: string;
  paid: boolean;
  amount: number;
  note: string;
  paymentDate?: string;
  paymentMethod?: PaymentMethod;
}

export interface BudgetEvent {
  id: number;
  name: string;
  date: string;
  budget: number;
  spent: number;
  category: EventCategory;
  done: boolean;
  notes: string;
  paidBy?: string;
}

export interface CashEntry {
  id: number;
  date: string;
  desc: string;
  amount: number;       // positive = income, negative = expense
  type: CashType;
  paidBy: string;
  linkedEventId?: number | null;
}

export interface GiftIdea {
  id: number;
  icon: string;
  name: string;
  forWhom: string;
  priceRange: string;
  tag: string;
  notes: string;
}

export interface AppSettings {
  totalStudents: number;
  feePerStudent: number;
  carryOver: number;
  year: string;
  className: string;
}

export interface AppState {
  students: Student[];
  events: BudgetEvent[];
  cashLog: CashEntry[];
  gifts: GiftIdea[];
  settings: AppSettings;
  syncing: boolean;
  lastSynced: Date | null;
}

export const CAT_COLORS: Record<EventCategory, { bg: string; text: string; dot: string }> = {
  'מתנות': { bg: '#fdf2f8', text: '#be185d', dot: '#ec4899' },
  'פעילות': { bg: '#eff6ff', text: '#1d4ed8', dot: '#3b82f6' },
  'חג':     { bg: '#f0fdf4', text: '#166534', dot: '#22c55e' },
  'ארוע':   { bg: '#faf5ff', text: '#7e22ce', dot: '#a855f7' },
  'שונות':  { bg: '#fff7ed', text: '#c2410c', dot: '#f97316' },
};

export const EVENT_CATEGORIES: EventCategory[] = ['מתנות', 'פעילות', 'חג', 'ארוע', 'שונות'];

