    88→function useStore(key, def) {
    89→  const [val, setVal] = useState(() => {
    90→    try {
    91→      const s = window.appStore?.[key];
    92→      return s ? JSON.parse(s) : def;
    93→    } catch { return def; }
    94→  });
    95→  const set = (v) => {
    96→    const next = typeof v === "function" ? v(val) : v;
    97→    if (!window.appStore) window.appStore = {};
    98→    window.appStore[key] = JSON.stringify(next);
    99→    setVal(next);
   100→  };
   101→  return [val, set];
   102→}
