   131→      }} />
   132→    </div>
   133→  );
   134→}
   135→
   136→function StatBox({ icon, label, value, color }) {
   137→  return (
   138→    <div style={{
   139→      background: "white", borderRadius: 16, padding: "14px 12px",
   140→      boxShadow: "0 4px 20px rgba(0,0,0,0.09)", flex: "0 0 auto", minWidth: 100, textAlign: "center"
