   143→      <div style={{ fontWeight: 900, fontSize: 17, color, marginTop: 2 }}>{value}</div>
   144→      <div style={{ fontSize: 10, color: "#94a3b8", fontWeight: 500, marginTop: 1 }}>{label}</div>
   145→    </div>
   146→  );
   147→}
