   195→                <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 1 }}>{event.date}</div>
   196→              </div>
   197→            </div>
   198→            <div style={{ textAlign: "left" }}>
   199→              <div style={{ fontWeight: 800, fontSize: 15, color: "#0f172a" }}>₪{event.budget.toLocaleString()}</div>
