   208→
   209→// ============ BUDGET ============
   210→function BudgetTab({ events, setEvents }) {
   211→  const [showAdd, setShowAdd] = useState(false);
   212→  const [filter, setFilter] = useState("הכל");
   213→  const [newEvent, setNewEvent] = useState({ name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "" });
   214→  const [editing, setEditing] = useState(null);
   215→
   216→  const cats = ["הכל", ...Object.keys(CAT_COLORS)];
   217→  const filtered = filter === "הכל" ? events : events.filter(e => e.category === filter);
   218→  const totalBudget = events.reduce((s, e) => s + e.budget, 0);
   219→  const totalSpent = events.reduce((s, e) => s + e.spent, 0);
   220→
   221→  const addEvent = () => {
   222→    if (!newEvent.name) return;
   223→    const e = {
   224→      id: Date.now(), ...newEvent,
   225→      budget: Number(newEvent.budget) || 0,
   226→      spent: Number(newEvent.spent) || 0,
   227→      done: false
   228→    };
   229→    setEvents([...events, e]);
   230→    setNewEvent({ name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "" });
   231→    setShowAdd(false);
   232→  };
   233→
   234→  const updateSpent = (id, val) => {
   235→    setEvents(events.map(e => e.id === id ? { ...e, spent: Number(val) || 0 } : e));
   236→  };
   237→
   238→  const toggleDone = (id) => {
