   263→            <div style={{ fontWeight: 900, fontSize: 16, color: x.c }}>{x.v}</div>
   264→            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
   265→          </div>
   266→        ))}
   267→      </div>
   268→
   269→      {/* Filters */}
   270→      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 14, paddingBottom: 2 }}>
   271→        {cats.map(c => (
   272→          <button key={c} onClick={() => setFilter(c)} style={{
   273→            padding: "6px 12px", borderRadius: 20, border: "none", cursor: "pointer",
   274→            fontFamily: "inherit", fontWeight: 600, fontSize: 12, whiteSpace: "nowrap",
   275→            background: filter === c ? "#7c3aed" : "#f1f5f9",
   276→            color: filter === c ? "white" : "#64748b",
   277→          }}>{c}</button>
   278→        ))}
   279→      </div>
   280→
   281→      {/* Events */}
