   301→              <div style={{ textAlign: "left", flexShrink: 0, marginRight: 8 }}>
   302→                <div style={{ fontWeight: 900, fontSize: 16, color: "#0f172a" }}>₪{event.budget.toLocaleString()}</div>
   303→                <div style={{ fontSize: 11, color: "#94a3b8" }}>תקציב</div>
   304→              </div>
   305→            </div>
   306→            {/* Spent editor */}
   307→            <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4 }}>
