   365→// ============ COLLECT ============
   366→function CollectTab({ students, setStudents }) {
   367→  const [search, setSearch] = useState("");
   368→  const [showAdd, setShowAdd] = useState(false);
   369→  const [newName, setNewName] = useState("");
