   372→
   373→  const paidCount = students.filter(s => s.paid).length;
   374→  const totalCollected = students.reduce((s, st) => s + (st.amount || 0), 0);
   375→  const filtered = students.filter(s => s.name.includes(search));
   376→
   377→  const toggle = (id) => setStudents(students.map(s => s.id === id
   378→    ? { ...s, paid: !s.paid, amount: !s.paid ? 500 : s.amount }
   379→    : s));
   380→
   381→  const addStudent = () => {
   382→    if (!newName.trim()) return;
   383→    setStudents([...students, {
   384→      id: Date.now(), name: newName.trim(), paid: false, amount: 0, note: ""
   385→    }]);
   386→    setNewName(""); setShowAdd(false);
   387→  };
   388→
   389→  const saveNote = (id) => {
   390→    setStudents(students.map(s => s.id === id ? { ...s, note: noteVal } : s));
