   408→            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
   409→          </div>
   410→        ))}
   411→      </div>
   412→
   413→      <input placeholder="🔍 חפשי תלמיד..." value={search}
   414→        onChange={e => setSearch(e.target.value)}
