   417→
   418→      <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg, #059669, #7c3aed)" />
   419→      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#94a3b8", marginBottom: 14, marginTop: 4 }}>
   420→        <span>0%</span>
   421→        <span>{Math.round((paidCount / students.length) * 100)}% שולם</span>
   422→        <span>100%</span>
   423→      </div>
   424→
   425→      {filtered.map(s => (
   426→        <div key={s.id} style={{
   427→          background: "white", borderRadius: 14, padding: "12px 14px", marginBottom: 8,
   428→          boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
   429→          borderRight: `4px solid ${s.paid ? "#059669" : "#e2e8f0"}`
   430→        }}>
   431→          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
   432→            <div style={{ flex: 1 }}>
   433→              <div style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>
   434→                {s.id <= 27 ? `${s.id}. ` : ""}{s.name}
   435→              </div>
   436→              {s.note ? (
   437→                <div style={{ fontSize: 11, color: "#f59e0b", marginTop: 2 }}>📝 {s.note}</div>
