   441→                  <input value={noteVal} onChange={e => setNoteVal(e.target.value)}
   442→                    placeholder="הערה..." autoFocus
   443→                    style={{ ...inputStyle, marginBottom: 0, flex: 1, fontSize: 12 }} />
   444→                  <button onClick={() => saveNote(s.id)} style={{ ...btnStyle("#7c3aed"), padding: "4px 10px", fontSize: 12 }}>שמור</button>
   445→                </div>
   446→              ) : (
   447→                <button onClick={() => { setEditNote(s.id); setNoteVal(s.note || ""); }}
   448→                  style={{ background: "none", border: "none", color: "#94a3b8", fontSize: 11, cursor: "pointer", padding: "2px 0", fontFamily: "inherit" }}>
   449→                  + הוסיפי הערה
