   476→        <button onClick={() => setShowAdd(true)} style={{
   477→          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
   478→          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
   479→          cursor: "pointer", fontFamily: "inherit", marginTop: 4
   480→        }}>+ הוסיפי תלמיד/ה</button>
   481→      )}
   482→    </div>
   483→  );
   484→}
