   581→// ============ CASH ============
   582→function CashTab({ cashLog, setCashLog }) {
   583→  const [showAdd, setShowAdd] = useState(false);
   584→  const [newEntry, setNewEntry] = useState({ date: "", desc: "", amount: "", type: "income", paidBy: "" });
   585→
   586→  const balance = cashLog.reduce((s, c) => s + c.amount, 0);
   587→  const totalIn = cashLog.filter(c => c.amount > 0).reduce((s, c) => s + c.amount, 0);
   588→  const totalOut = cashLog.filter(c => c.amount < 0).reduce((s, c) => s + c.amount, 0);
   589→
   590→  const addEntry = () => {
   591→    if (!newEntry.desc || !newEntry.amount) return;
   592→    const amt = Number(newEntry.amount) * (newEntry.type === "expense" ? -1 : 1);
   593→    setCashLog([...cashLog, { id: Date.now(), ...newEntry, amount: amt }]);
   594→    setNewEntry({ date: "", desc: "", amount: "", type: "income", paidBy: "" });
   595→    setShowAdd(false);
   596→  };
   597→
   598→  const remove = (id) => setCashLog(cashLog.filter(c => c.id !== id));
   599→
   600→  return (
   601→    <div>
   602→      <div style={{
   603→        background: "linear-gradient(135deg, #1e293b, #0f172a)",
   604→        borderRadius: 20, padding: 20, color: "white", marginBottom: 16
   605→      }}>
   606→        <div style={{ opacity: 0.6, fontSize: 13, marginBottom: 4 }}>יתרת מזומן</div>
   607→        <div style={{ fontSize: 38, fontWeight: 900, letterSpacing: -1 }}>
   608→          ₪{Math.abs(balance).toLocaleString()}
   609→        </div>
   610→        <div style={{ display: "flex", gap: 20, marginTop: 14 }}>
   611→          <div>
   612→            <div style={{ opacity: 0.5, fontSize: 11 }}>נכנס</div>
   613→            <div style={{ fontWeight: 700, color: "#4ade80" }}>+₪{totalIn.toLocaleString()}</div>
   614→          </div>
   615→          <div>
   616→            <div style={{ opacity: 0.5, fontSize: 11 }}>יצא</div>
   617→            <div style={{ fontWeight: 700, color: "#f87171" }}>₪{Math.abs(totalOut).toLocaleString()}</div>
   618→          </div>
   619→        </div>
   620→      </div>
   621→
   622→      <h3 style={{ fontWeight: 800, fontSize: 15, color: "#1e293b", marginBottom: 10 }}>יומן תנועות</h3>
   623→
   624→      {[...cashLog].reverse().map(entry => (
   625→        <div key={entry.id} style={{
   626→          background: "white", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
   627→          boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
   628→          display: "flex", justifyContent: "space-between", alignItems: "center",
   629→          borderRight: `4px solid ${entry.amount > 0 ? "#4ade80" : "#f87171"}`
   630→        }}>
   631→          <div>
   632→            <div style={{ fontWeight: 600, fontSize: 14, color: "#0f172a" }}>{entry.desc}</div>
   633→            <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
   634→              {entry.date}
   635→              {entry.paidBy && ` • שילם/ה: ${entry.paidBy}`}
   636→            </div>
   637→          </div>
   638→          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
   639→            <div style={{
   640→              fontWeight: 800, fontSize: 16,
   641→              color: entry.amount > 0 ? "#059669" : "#ef4444"
   642→            }}>
   643→              {entry.amount > 0 ? "+" : ""}₪{Math.abs(entry.amount).toLocaleString()}
   644→            </div>
   645→            <button onClick={() => remove(entry.id)} style={{
   646→              background: "none", border: "none", cursor: "pointer",
   647→              color: "#cbd5e1", fontSize: 14, padding: 0
   648→            }}>✕</button>
   649→          </div>
   650→        </div>
