   801→            }}>{t.label}</span>
   802→            {tab === t.id && (
   803→              <div style={{
   804→                width: 18, height: 3, borderRadius: 100, marginTop: 1,
   805→                background: "linear-gradient(90deg, #7c3aed, #db2777)"
