  { id: 6, icon: "🥋", name: "הפעלת ג׳ודו שכבתית", forWhom: "שכבה", priceRange: "50₪ לילד", tag: "סוף שנה", notes: "" },
  { id: 7, icon: "🍕", name: "פיצה שכבתית", forWhom: "שכבה", priceRange: "30-40₪ לילד", tag: "סוף שנה", notes: "" },
  { id: 8, icon: "🎨", name: "הפעלת אמנות", forWhom: "כיתה", priceRange: "40₪ לילד", tag: "יום המשפחה", notes: "" },
];

const CAT_COLORS = {
  "מתנות": { bg: "#fdf2f8", text: "#be185d", dot: "#ec4899" },
  "פעילות": { bg: "#eff6ff", text: "#1d4ed8", dot: "#3b82f6" },
  "חג": { bg: "#f0fdf4", text: "#166534", dot: "#22c55e" },
  "ארוע": { bg: "#faf5ff", text: "#7e22ce", dot: "#a855f7" },
  "שונות": { bg: "#fff7ed", text: "#c2410c", dot: "#f97316" },
};

const TABS = [
  { id: "home", label: "בית", icon: "🏠" },
  { id: "budget", label: "תקציב", icon: "📊" },
  { id: "collect", label: "גבייה", icon: "💰" },
  { id: "gifts", label: "רעיונות", icon: "🎁" },
  { id: "cash", label: "מזומן", icon: "💵" },
];

function useStore(key, def) {
  const [val, setVal] = useState(() => {
    try {
      const s = window.appStore?.[key];
      return s ? JSON.parse(s) : def;
    } catch { return def; }
  });
  const set = (v) => {
    const next = typeof v === "function" ? v(val) : v;
    if (!window.appStore) window.appStore = {};
    window.appStore[key] = JSON.stringify(next);
    setVal(next);
  };
  return [val, set];
}

function Card({ children, style = {} }) {
  return (
    <div style={{
      background: "white", borderRadius: 16, padding: 16,
      boxShadow: "0 2px 16px rgba(0,0,0,0.07)", marginBottom: 12, ...style
    }}>
