  );
}

function Badge({ text, cat }) {
  const c = CAT_COLORS[cat] || CAT_COLORS["שונות"];
  return (
    <span style={{
      fontSize: 10, fontWeight: 700, padding: "2px 8px", borderRadius: 20,
      background: c.bg, color: c.text
    }}>{text}</span>
  );
}

function ProgressBar({ pct, color = "#7c3aed" }) {
  return (
    <div style={{ background: "#f1f5f9", borderRadius: 100, height: 7, overflow: "hidden", marginTop: 8 }}>
