        width: `${Math.min(pct, 100)}%`, transition: "width 0.5s ease"
      }} />
    </div>
  );
}

function StatBox({ icon, label, value, color }) {
  return (
    <div style={{
      background: "white", borderRadius: 16, padding: "14px 12px",
      boxShadow: "0 4px 20px rgba(0,0,0,0.09)", flex: "0 0 auto", minWidth: 100, textAlign: "center"
    }}>
