      <div style={{ fontWeight: 900, fontSize: 17, color, marginTop: 2 }}>{value}</div>
      <div style={{ fontSize: 10, color: "#94a3b8", fontWeight: 500, marginTop: 1 }}>{label}</div>
    </div>
  );
}

// ============ HOME ============
function HomeTab({ students, events, cashLog }) {
  const paidCount = students.filter(s => s.paid).length;
  const totalBudget = events.reduce((s, e) => s + e.budget, 0);
  const totalSpent = events.reduce((s, e) => s + e.spent, 0);
  const balance = cashLog.reduce((s, c) => s + c.amount, 0);
  const upcoming = events.filter(e => !e.done).slice(0, 5);
  const unpaid = students.filter(s => !s.paid);

  return (
    <div>
      <div style={{ marginBottom: 20 }}>
        <h2 style={{ fontWeight: 800, fontSize: 16, color: "#1e293b", marginBottom: 12 }}>סיכום שנתי</h2>
        <div style={{ display: "flex", gap: 10, overflowX: "auto", paddingBottom: 4 }}>
          <StatBox icon="📊" label="תקציב" value={`₪${totalBudget.toLocaleString()}`} color="#7c3aed" />
          <StatBox icon="✅" label="שולם" value={`₪${totalSpent.toLocaleString()}`} color="#db2777" />
          <StatBox icon="💰" label="נשאר" value={`₪${(totalBudget - totalSpent).toLocaleString()}`} color="#059669" />
          <StatBox icon="💵" label="מזומן" value={`₪${balance.toLocaleString()}`} color="#ea580c" />
        </div>
      </div>

      <Card>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
          <span style={{ fontWeight: 700, fontSize: 14 }}>סטטוס גבייה</span>
          <span style={{ fontWeight: 800, color: "#7c3aed" }}>{paidCount}/{students.length}</span>
        </div>
        <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg, #7c3aed, #db2777)" />
        {unpaid.length > 0 && (
          <div style={{ marginTop: 10, fontSize: 12, color: "#64748b" }}>
            <span style={{ fontWeight: 600 }}>טרם שילמו: </span>
            {unpaid.map(s => s.name).join(" • ")}
          </div>
        )}
      </Card>

      <h2 style={{ fontWeight: 800, fontSize: 16, color: "#1e293b", marginBottom: 10 }}>ארועים קרובים</h2>
      {upcoming.map(event => (
        <Card key={event.id} style={{ padding: "12px 14px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
              <div style={{
                width: 10, height: 10, borderRadius: "50%",
                background: CAT_COLORS[event.category]?.dot || "#94a3b8", flexShrink: 0
              }} />
              <div>
                <div style={{ fontWeight: 700, fontSize: 14 }}>{event.name}</div>
                <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 1 }}>{event.date}</div>
              </div>
            </div>
            <div style={{ textAlign: "left" }}>
              <div style={{ fontWeight: 800, fontSize: 15, color: "#0f172a" }}>₪{event.budget.toLocaleString()}</div>
              <Badge text={event.category} cat={event.category} />
            </div>
          </div>
        </Card>
      ))}
    </div>
  );
}

// ============ BUDGET ============
function BudgetTab({ events, setEvents }) {
  const [showAdd, setShowAdd] = useState(false);
  const [filter, setFilter] = useState("הכל");
  const [newEvent, setNewEvent] = useState({ name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "" });
  const [editing, setEditing] = useState(null);

  const cats = ["הכל", ...Object.keys(CAT_COLORS)];
  const filtered = filter === "הכל" ? events : events.filter(e => e.category === filter);
  const totalBudget = events.reduce((s, e) => s + e.budget, 0);
  const totalSpent = events.reduce((s, e) => s + e.spent, 0);

  const addEvent = () => {
    if (!newEvent.name) return;
    const e = {
      id: Date.now(), ...newEvent,
      budget: Number(newEvent.budget) || 0,
      spent: Number(newEvent.spent) || 0,
      done: false
    };
    setEvents([...events, e]);
    setNewEvent({ name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "" });
    setShowAdd(false);
  };

  const updateSpent = (id, val) => {
    setEvents(events.map(e => e.id === id ? { ...e, spent: Number(val) || 0 } : e));
  };

  const toggleDone = (id) => {
    setEvents(events.map(e => e.id === id ? { ...e, done: !e.done } : e));
  };

  const inp = (field, ph, type = "text") => (
    <input
      type={type} placeholder={ph} value={newEvent[field]}
      onChange={e => setNewEvent({ ...newEvent, [field]: e.target.value })}
      style={inputStyle}
    />
  );

  return (
    <div>
      {/* Summary */}
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { l: "תקציב כולל", v: `₪${totalBudget.toLocaleString()}`, c: "#7c3aed" },
          { l: "שולם", v: `₪${totalSpent.toLocaleString()}`, c: "#db2777" },
          { l: "נשאר", v: `₪${(totalBudget - totalSpent).toLocaleString()}`, c: "#059669" },
        ].map(x => (
          <div key={x.l} style={{
            background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center",
            boxShadow: "0 2px 10px rgba(0,0,0,0.07)"
          }}>
            <div style={{ fontWeight: 900, fontSize: 16, color: x.c }}>{x.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 14, paddingBottom: 2 }}>
        {cats.map(c => (
          <button key={c} onClick={() => setFilter(c)} style={{
            padding: "6px 12px", borderRadius: 20, border: "none", cursor: "pointer",
            fontFamily: "inherit", fontWeight: 600, fontSize: 12, whiteSpace: "nowrap",
            background: filter === c ? "#7c3aed" : "#f1f5f9",
            color: filter === c ? "white" : "#64748b",
          }}>{c}</button>
        ))}
      </div>

      {/* Events */}
      {filtered.map(event => {
        const pct = event.budget > 0 ? (event.spent / event.budget) * 100 : 0;
        return (
          <Card key={event.id} style={{ opacity: event.done ? 0.65 : 1, padding: "12px 14px" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
                  <button onClick={() => toggleDone(event.id)} style={{
                    background: "none", border: "none", cursor: "pointer",
                    fontSize: 16, padding: 0, lineHeight: 1
                  }}>{event.done ? "✅" : "⬜"}</button>
                  <span style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>{event.name}</span>
                </div>
                <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 6 }}>
                  <Badge text={event.category} cat={event.category} />
                  <span style={{ fontSize: 11, color: "#94a3b8" }}>{event.date}</span>
                </div>
                {event.notes && <div style={{ fontSize: 11, color: "#64748b", marginBottom: 6 }}>📝 {event.notes}</div>}
              </div>
              <div style={{ textAlign: "left", flexShrink: 0, marginRight: 8 }}>
                <div style={{ fontWeight: 900, fontSize: 16, color: "#0f172a" }}>₪{event.budget.toLocaleString()}</div>
                <div style={{ fontSize: 11, color: "#94a3b8" }}>תקציב</div>
              </div>
            </div>
            {/* Spent editor */}
            <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 4 }}>
              <span style={{ fontSize: 12, color: "#64748b" }}>שולם:</span>
              <input
                type="number"
                value={event.spent || ""}
                onChange={e => updateSpent(event.id, e.target.value)}
                placeholder="0"
                style={{
                  width: 70, padding: "4px 8px", borderRadius: 8, border: "1.5px solid #e2e8f0",
                  fontSize: 13, fontFamily: "inherit", fontWeight: 700, color: "#db2777"
                }}
              />
              <span style={{ fontSize: 11, color: "#94a3b8" }}>
                {event.spent > 0 && `יתרה: ₪${(event.budget - event.spent).toLocaleString()}`}
              </span>
            </div>
            {event.spent > 0 && (
              <ProgressBar
                pct={pct}
                color={pct > 100 ? "#ef4444" : pct > 80 ? "#f59e0b" : "#7c3aed"}
              />
            )}
          </Card>
        );
      })}

      {/* Add Event */}
      {showAdd ? (
        <Card>
          <h3 style={{ fontWeight: 700, margin: "0 0 12px", fontSize: 15 }}>➕ ארוע חדש</h3>
          {inp("name", "שם הארוע")}
          {inp("date", "תאריך")}
          <div style={{ display: "flex", gap: 8 }}>
            {inp("budget", "תקציב ₪", "number")}
            {inp("spent", "שולם ₪", "number")}
          </div>
          <select value={newEvent.category}
            onChange={e => setNewEvent({ ...newEvent, category: e.target.value })}
            style={{ ...inputStyle, marginBottom: 8 }}>
            {Object.keys(CAT_COLORS).map(c => <option key={c}>{c}</option>)}
          </select>
          {inp("notes", "הערות")}
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addEvent} style={btnStyle("#7c3aed")}>שמור</button>
            <button onClick={() => setShowAdd(false)} style={btnStyle("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit"
        }}>+ הוסיפי ארוע</button>
      )}
    </div>
  );
}

// ============ COLLECT ============
function CollectTab({ students, setStudents }) {
  const [search, setSearch] = useState("");
  const [showAdd, setShowAdd] = useState(false);
  const [newName, setNewName] = useState("");
  const [editNote, setEditNote] = useState(null);
  const [noteVal, setNoteVal] = useState("");

  const paidCount = students.filter(s => s.paid).length;
  const totalCollected = students.reduce((s, st) => s + (st.amount || 0), 0);
  const filtered = students.filter(s => s.name.includes(search));

  const toggle = (id) => setStudents(students.map(s => s.id === id
    ? { ...s, paid: !s.paid, amount: !s.paid ? 500 : s.amount }
    : s));

  const addStudent = () => {
    if (!newName.trim()) return;
    setStudents([...students, {
      id: Date.now(), name: newName.trim(), paid: false, amount: 0, note: ""
    }]);
    setNewName(""); setShowAdd(false);
  };

  const saveNote = (id) => {
    setStudents(students.map(s => s.id === id ? { ...s, note: noteVal } : s));
    setEditNote(null);
  };

  return (
    <div>
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
        {[
          { l: "שילמו", v: paidCount, c: "#059669", icon: "✅" },
          { l: "לא שילמו", v: students.length - paidCount, c: "#ef4444", icon: "❌" },
          { l: "נגבה", v: `₪${totalCollected.toLocaleString()}`, c: "#7c3aed", icon: "💰" },
        ].map(x => (
          <div key={x.l} style={{
            background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center",
            boxShadow: "0 2px 10px rgba(0,0,0,0.07)"
          }}>
            <div style={{ fontSize: 18 }}>{x.icon}</div>
            <div style={{ fontWeight: 900, fontSize: 18, color: x.c }}>{x.v}</div>
            <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
          </div>
        ))}
      </div>

      <input placeholder="🔍 חפשי תלמיד..." value={search}
        onChange={e => setSearch(e.target.value)}
        style={{ ...inputStyle, marginBottom: 12 }}
      />

      <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg, #059669, #7c3aed)" />
      <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#94a3b8", marginBottom: 14, marginTop: 4 }}>
        <span>0%</span>
        <span>{Math.round((paidCount / students.length) * 100)}% שולם</span>
        <span>100%</span>
      </div>

      {filtered.map(s => (
        <div key={s.id} style={{
          background: "white", borderRadius: 14, padding: "12px 14px", marginBottom: 8,
          boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
          borderRight: `4px solid ${s.paid ? "#059669" : "#e2e8f0"}`
        }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>
                {s.id <= 27 ? `${s.id}. ` : ""}{s.name}
              </div>
              {s.note ? (
                <div style={{ fontSize: 11, color: "#f59e0b", marginTop: 2 }}>📝 {s.note}</div>
              ) : null}
              {editNote === s.id ? (
                <div style={{ display: "flex", gap: 6, marginTop: 6 }}>
                  <input value={noteVal} onChange={e => setNoteVal(e.target.value)}
                    placeholder="הערה..." autoFocus
                    style={{ ...inputStyle, marginBottom: 0, flex: 1, fontSize: 12 }} />
                  <button onClick={() => saveNote(s.id)} style={{ ...btnStyle("#7c3aed"), padding: "4px 10px", fontSize: 12 }}>שמור</button>
                </div>
              ) : (
                <button onClick={() => { setEditNote(s.id); setNoteVal(s.note || ""); }}
                  style={{ background: "none", border: "none", color: "#94a3b8", fontSize: 11, cursor: "pointer", padding: "2px 0", fontFamily: "inherit" }}>
                  + הוסיפי הערה
                </button>
              )}
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              {s.paid && <span style={{ fontSize: 12, fontWeight: 700, color: "#059669" }}>₪{s.amount}</span>}
              <button onClick={() => toggle(s.id)} style={{
                width: 36, height: 36, borderRadius: "50%", border: "none", cursor: "pointer",
                background: s.paid ? "#dcfce7" : "#fee2e2", fontSize: 18
              }}>
                {s.paid ? "✅" : "❌"}
              </button>
            </div>
          </div>
        </div>
      ))}

      {showAdd ? (
        <Card>
          <input value={newName} onChange={e => setNewName(e.target.value)}
            placeholder="שם התלמיד/ה" style={inputStyle} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addStudent} style={btnStyle("#7c3aed")}>הוסיפי</button>
            <button onClick={() => setShowAdd(false)} style={btnStyle("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 4
        }}>+ הוסיפי תלמיד/ה</button>
      )}
    </div>
  );
}

// ============ GIFTS ============
function GiftsTab({ gifts, setGifts }) {
  const [search, setSearch] = useState("");
  const [showAdd, setShowAdd] = useState(false);
  const [newGift, setNewGift] = useState({ icon: "🎁", name: "", forWhom: "", priceRange: "", tag: "", notes: "" });

  const filtered = gifts.filter(g =>
    g.name.includes(search) || g.tag.includes(search) || g.forWhom.includes(search)
  );

  const addGift = () => {
    if (!newGift.name) return;
    setGifts([...gifts, { ...newGift, id: Date.now() }]);
    setNewGift({ icon: "🎁", name: "", forWhom: "", priceRange: "", tag: "", notes: "" });
    setShowAdd(false);
  };

  const removeGift = (id) => setGifts(gifts.filter(g => g.id !== id));

  const EMOJIS = ["🎁", "🌸", "📚", "🌿", "🍪", "🥋", "🍕", "🎨", "🎉", "⭐", "🍰", "🎪"];

  return (
    <div>
      <input placeholder="🔍 חפשי רעיון..." value={search}
        onChange={e => setSearch(e.target.value)}
        style={{ ...inputStyle, marginBottom: 12 }}
      />
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
        {filtered.map(gift => (
          <div key={gift.id} style={{
            background: "white", borderRadius: 16, padding: 14,
            boxShadow: "0 2px 14px rgba(0,0,0,0.08)", position: "relative"
          }}>
            <button onClick={() => removeGift(gift.id)} style={{
              position: "absolute", top: 8, left: 8, background: "none", border: "none",
              cursor: "pointer", fontSize: 14, color: "#cbd5e1", padding: 0
            }}>✕</button>
            <div style={{ fontSize: 30, marginBottom: 6 }}>{gift.icon}</div>
            <div style={{ fontWeight: 700, fontSize: 13, color: "#0f172a", marginBottom: 4 }}>{gift.name}</div>
            {gift.forWhom && <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 4 }}>עבור: {gift.forWhom}</div>}
            {gift.notes && <div style={{ fontSize: 11, color: "#64748b", marginBottom: 6 }}>{gift.notes}</div>}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 4 }}>
              {gift.tag && (
                <span style={{
                  fontSize: 10, fontWeight: 700, background: "#f0fdf4",
                  color: "#059669", borderRadius: 8, padding: "2px 6px"
                }}>{gift.tag}</span>
              )}
              {gift.priceRange && (
                <span style={{ fontSize: 12, fontWeight: 700, color: "#7c3aed" }}>{gift.priceRange}</span>
              )}
            </div>
          </div>
        ))}
      </div>

      {showAdd ? (
        <Card style={{ marginTop: 12 }}>
          <h3 style={{ fontWeight: 700, margin: "0 0 10px" }}>➕ רעיון חדש</h3>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 8 }}>
            {EMOJIS.map(e => (
              <button key={e} onClick={() => setNewGift({ ...newGift, icon: e })}
                style={{
                  fontSize: 20, background: newGift.icon === e ? "#ede9fe" : "#f8fafc",
                  border: newGift.icon === e ? "2px solid #7c3aed" : "2px solid transparent",
                  borderRadius: 8, padding: 4, cursor: "pointer"
                }}>{e}</button>
            ))}
          </div>
          <input placeholder="שם הרעיון" value={newGift.name}
            onChange={e => setNewGift({ ...newGift, name: e.target.value })} style={inputStyle} />
          <input placeholder="עבור מי" value={newGift.forWhom}
            onChange={e => setNewGift({ ...newGift, forWhom: e.target.value })} style={inputStyle} />
          <input placeholder="טווח מחירים" value={newGift.priceRange}
            onChange={e => setNewGift({ ...newGift, priceRange: e.target.value })} style={inputStyle} />
          <input placeholder="לאיזה אירוע / תג" value={newGift.tag}
            onChange={e => setNewGift({ ...newGift, tag: e.target.value })} style={inputStyle} />
          <input placeholder="הערות" value={newGift.notes}
            onChange={e => setNewGift({ ...newGift, notes: e.target.value })} style={inputStyle} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addGift} style={btnStyle("#7c3aed")}>שמור</button>
            <button onClick={() => setShowAdd(false)} style={btnStyle("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 12
        }}>+ הוסיפי רעיון</button>
      )}
    </div>
  );
}

// ============ CASH ============
function CashTab({ cashLog, setCashLog }) {
  const [showAdd, setShowAdd] = useState(false);
  const [newEntry, setNewEntry] = useState({ date: "", desc: "", amount: "", type: "income", paidBy: "" });

  const balance = cashLog.reduce((s, c) => s + c.amount, 0);
  const totalIn = cashLog.filter(c => c.amount > 0).reduce((s, c) => s + c.amount, 0);
  const totalOut = cashLog.filter(c => c.amount < 0).reduce((s, c) => s + c.amount, 0);

  const addEntry = () => {
    if (!newEntry.desc || !newEntry.amount) return;
    const amt = Number(newEntry.amount) * (newEntry.type === "expense" ? -1 : 1);
    setCashLog([...cashLog, { id: Date.now(), ...newEntry, amount: amt }]);
    setNewEntry({ date: "", desc: "", amount: "", type: "income", paidBy: "" });
    setShowAdd(false);
  };

  const remove = (id) => setCashLog(cashLog.filter(c => c.id !== id));

  return (
    <div>
      <div style={{
        background: "linear-gradient(135deg, #1e293b, #0f172a)",
        borderRadius: 20, padding: 20, color: "white", marginBottom: 16
      }}>
        <div style={{ opacity: 0.6, fontSize: 13, marginBottom: 4 }}>יתרת מזומן</div>
        <div style={{ fontSize: 38, fontWeight: 900, letterSpacing: -1 }}>
          ₪{Math.abs(balance).toLocaleString()}
        </div>
        <div style={{ display: "flex", gap: 20, marginTop: 14 }}>
          <div>
            <div style={{ opacity: 0.5, fontSize: 11 }}>נכנס</div>
            <div style={{ fontWeight: 700, color: "#4ade80" }}>+₪{totalIn.toLocaleString()}</div>
          </div>
          <div>
            <div style={{ opacity: 0.5, fontSize: 11 }}>יצא</div>
            <div style={{ fontWeight: 700, color: "#f87171" }}>₪{Math.abs(totalOut).toLocaleString()}</div>
          </div>
        </div>
      </div>

      <h3 style={{ fontWeight: 800, fontSize: 15, color: "#1e293b", marginBottom: 10 }}>יומן תנועות</h3>

      {[...cashLog].reverse().map(entry => (
        <div key={entry.id} style={{
          background: "white", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
          boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
          display: "flex", justifyContent: "space-between", alignItems: "center",
          borderRight: `4px solid ${entry.amount > 0 ? "#4ade80" : "#f87171"}`
        }}>
          <div>
            <div style={{ fontWeight: 600, fontSize: 14, color: "#0f172a" }}>{entry.desc}</div>
            <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
              {entry.date}
              {entry.paidBy && ` • שילם/ה: ${entry.paidBy}`}
            </div>
          </div>
          <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
            <div style={{
              fontWeight: 800, fontSize: 16,
              color: entry.amount > 0 ? "#059669" : "#ef4444"
            }}>
              {entry.amount > 0 ? "+" : ""}₪{Math.abs(entry.amount).toLocaleString()}
            </div>
            <button onClick={() => remove(entry.id)} style={{
              background: "none", border: "none", cursor: "pointer",
              color: "#cbd5e1", fontSize: 14, padding: 0
            }}>✕</button>
          </div>
        </div>
      ))}

      {showAdd ? (
        <Card style={{ marginTop: 4 }}>
          <h3 style={{ fontWeight: 700, margin: "0 0 10px" }}>➕ תנועה חדשה</h3>
          <div style={{ display: "flex", gap: 8, marginBottom: 0 }}>
            {["income", "expense"].map(t => (
              <button key={t} onClick={() => setNewEntry({ ...newEntry, type: t })}
                style={{
                  flex: 1, padding: "10px 0", borderRadius: 10, border: "none",
                  cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13,
                  background: newEntry.type === t ? (t === "income" ? "#dcfce7" : "#fee2e2") : "#f1f5f9",
                  color: newEntry.type === t ? (t === "income" ? "#059669" : "#ef4444") : "#94a3b8",
                  marginBottom: 8
                }}>
                {t === "income" ? "✅ הכנסה" : "📤 הוצאה"}
              </button>
            ))}
          </div>
          <input placeholder="תיאור" value={newEntry.desc}
            onChange={e => setNewEntry({ ...newEntry, desc: e.target.value })} style={inputStyle} />
          <div style={{ display: "flex", gap: 8 }}>
            <input type="number" placeholder="סכום ₪" value={newEntry.amount}
              onChange={e => setNewEntry({ ...newEntry, amount: e.target.value })} style={{ ...inputStyle, flex: 1 }} />
            <input placeholder="תאריך" value={newEntry.date}
              onChange={e => setNewEntry({ ...newEntry, date: e.target.value })} style={{ ...inputStyle, flex: 1 }} />
          </div>
          <input placeholder="שולם ע״י (אופציונלי)" value={newEntry.paidBy}
            onChange={e => setNewEntry({ ...newEntry, paidBy: e.target.value })} style={inputStyle} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={addEntry} style={btnStyle("#0f172a")}>שמור תנועה</button>
            <button onClick={() => setShowAdd(false)} style={btnStyle("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
