        }} />
        <div style={{ position: "relative" }}>
          <div style={{ color: "white", fontWeight: 900, fontSize: 20, marginBottom: 2 }}>
            🌟 ועד הורים — כיתה ו׳
          </div>
          <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 13 }}>
            תשפ״ד–תשפ״ה • ניהול תקציב שנתי
          </div>
        </div>
      </div>

      {/* Floating stats */}
      <div style={{
        display: "flex", gap: 8, padding: "0 14px",
        marginTop: -38, position: "relative", zIndex: 10,
        overflowX: "auto", paddingBottom: 4
      }}>
        {(() => {
          const paid = students.filter(s => s.paid).length;
          const budget = events.reduce((s, e) => s + e.budget, 0);
          const spent = events.reduce((s, e) => s + e.spent, 0);
          const cash = cashLog.reduce((s, c) => s + c.amount, 0);
          return [
            { icon: "📊", l: "תקציב", v: `₪${budget.toLocaleString()}`, c: "#7c3aed" },
            { icon: "✅", l: "שולם", v: `₪${spent.toLocaleString()}`, c: "#db2777" },
            { icon: "👧", l: "שילמו", v: `${paid}/${students.length}`, c: "#059669" },
            { icon: "💵", l: "מזומן", v: `₪${cash.toLocaleString()}`, c: "#ea580c" },
          ].map(s => (
            <div key={s.l} style={{
              background: "white", borderRadius: 14, padding: "12px 10px", minWidth: 90,
              boxShadow: "0 4px 18px rgba(0,0,0,0.12)", flex: "0 0 auto", textAlign: "center"
            }}>
              <div style={{ fontSize: 18 }}>{s.icon}</div>
              <div style={{ fontWeight: 900, fontSize: 14, color: s.c }}>{s.v}</div>
              <div style={{ fontSize: 10, color: "#94a3b8" }}>{s.l}</div>
            </div>
          ));
        })()}
      </div>

      {/* Content */}
      <div style={{ padding: "16px 14px 90px" }}>
        {tab === "home" && <HomeTab students={students} events={events} cashLog={cashLog} />}
        {tab === "budget" && <BudgetTab events={events} setEvents={setEvents} />}
        {tab === "collect" && <CollectTab students={students} setStudents={setStudents} />}
        {tab === "gifts" && <GiftsTab gifts={gifts} setGifts={setGifts} />}
        {tab === "cash" && <CashTab cashLog={cashLog} setCashLog={setCashLog} />}
      </div>

      {/* Bottom Nav */}
      <div style={{
        position: "fixed", bottom: 0, right: 0, left: 0, maxWidth: 480, margin: "0 auto",
        background: "white", borderTop: "1px solid #f1f5f9",
        display: "flex", padding: "6px 0 10px",
        boxShadow: "0 -8px 30px rgba(0,0,0,0.1)", zIndex: 100
      }}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)} style={{
            flex: 1, display: "flex", flexDirection: "column",
            alignItems: "center", gap: 2, background: "none", border: "none",
            cursor: "pointer", padding: "4px 0", transition: "all 0.15s"
          }}>
            <span style={{ fontSize: 19 }}>{t.icon}</span>
            <span style={{
              fontSize: 10, fontWeight: tab === t.id ? 800 : 400,
              color: tab === t.id ? "#7c3aed" : "#94a3b8", fontFamily: "inherit"
            }}>{t.label}</span>
            {tab === t.id && (
              <div style={{
                width: 18, height: 3, borderRadius: 100, marginTop: 1,
                background: "linear-gradient(90deg, #7c3aed, #db2777)"
              }} />
            )}
          </button>
        ))}
      </div>
    </div>
  );
}

