// src/hooks/useSheets.ts
// Offline-first hook: local state syncs to Google Sheets in background

import { useState, useCallback } from 'react';

const GAS_URL = import.meta.env.VITE_GAS_URL as string;

type SyncStatus = 'idle' | 'syncing' | 'success' | 'error' | 'offline';

export function useSheets() {
  const [syncStatus, setSyncStatus] = useState<SyncStatus>('idle');

  const isConfigured = Boolean(GAS_URL && GAS_URL !== 'undefined');

  async function get<T>(action: string): Promise<T | null> {
    if (!isConfigured) return null;
    try {
      setSyncStatus('syncing');
      const res = await fetch(`${GAS_URL}?action=${action}`);
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setSyncStatus('success');
      return data as T;
    } catch (err) {
      console.warn(`[Sheets] GET ${action} failed:`, err);
      setSyncStatus('error');
      return null;
    }
  }

  async function post<T>(action: string, body: object): Promise<T | null> {
    if (!isConfigured) return null;
    try {
      setSyncStatus('syncing');
      const res = await fetch(`${GAS_URL}?action=${action}`, {
        method: 'POST',
        body: JSON.stringify(body),
        headers: { 'Content-Type': 'application/json' },
        // GAS requires no-cors for direct POST from browser
        // Use a proxy or Apps Script CORS workaround if needed
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      setSyncStatus('success');
      return data as T;
    } catch (err) {
      console.warn(`[Sheets] POST ${action} failed:`, err);
      setSyncStatus('error');
      return null;
    }
  }

  return { get, post, syncStatus, isConfigured };
}

// ============================================================
// CORS NOTE for Google Apps Script:
// GAS Web Apps don't support CORS for POST with application/json.
// Solution: Use a Google Apps Script middleware that sets CORS headers,
// OR use a Cloudflare Worker / Vercel function as proxy,
// OR encode the body as URL params and use GET for everything.
//
// Recommended workaround — encode body in GET:
// GET ?action=updateStudent&data=<encodeURIComponent(JSON.stringify(body))>
// ============================================================

