// ============================================================
// ועד הורים App — Google Apps Script Backend
// Deploy as Web App: Execute as Me, Access: Anyone
// ============================================================

const SPREADSHEET_ID = 'YOUR_SPREADSHEET_ID_HERE'; // ← הכניסי את ה-ID מה-URL של הגיליון
const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

// ============================================================
// CORS + Router
// ============================================================
function doGet(e) {
  const action = e.parameter.action;
  let result;

  try {
    switch (action) {
      case 'getStudents':  result = getStudents(); break;
      case 'getEvents':    result = getEvents(); break;
      case 'getCash':      result = getCash(); break;
      case 'getGifts':     result = getGifts(); break;
      case 'getSettings':  result = getSettings(); break;
      default:             result = { error: 'Unknown action: ' + action };
    }
  } catch (err) {
    result = { error: err.message };
  }

  return ContentService
    .createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  const action = e.parameter.action;
  const body = JSON.parse(e.postData.contents);
  let result;

  try {
    switch (action) {
      case 'updateStudent':  result = updateStudent(body); break;
      case 'updateEvent':    result = updateEvent(body); break;
      case 'addCashEntry':   result = addCashEntry(body); break;
      case 'addGift':        result = addGift(body); break;
      case 'addEvent':       result = addEvent(body); break;
      case 'deleteGift':     result = deleteGift(body); break;
      case 'deleteCash':     result = deleteCash(body); break;
      default:               result = { error: 'Unknown action: ' + action };
    }
  } catch (err) {
    result = { error: err.message };
  }

  return ContentService
    .createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

// ============================================================
// STUDENTS — Sheet: "איסוף כסף"
// Columns: id | name | paid | amount | note | paymentDate | method
// ============================================================
function getStudents() {
  const sheet = getOrCreateSheet('איסוף כסף');
  const data = sheet.getDataRange().getValues();
  const students = [];

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    if (!row[1]) continue; // skip empty rows
    students.push({
      id: row[0] || i,
      name: row[1],
      paid: row[2] === true || row[2] === 1 || row[2] === 'TRUE',
      amount: Number(row[3]) || 0,
      note: row[4] || '',
      paymentDate: row[5] || '',
      paymentMethod: row[6] || '',
    });
  }
  return students;
}

function updateStudent(body) {
  const sheet = getOrCreateSheet('איסוף כסף');
  const data = sheet.getDataRange().getValues();

  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == body.id || data[i][1] === body.name) {
      sheet.getRange(i + 1, 3).setValue(body.paid ? 1 : 0);
      if (body.amount !== undefined) sheet.getRange(i + 1, 4).setValue(body.amount);
      if (body.note !== undefined)   sheet.getRange(i + 1, 5).setValue(body.note);
      if (body.paymentDate)          sheet.getRange(i + 1, 6).setValue(body.paymentDate);
      if (body.paymentMethod)        sheet.getRange(i + 1, 7).setValue(body.paymentMethod);
      return { success: true, row: i + 1 };
    }
  }
  return { error: 'Student not found: ' + body.id };
}

// ============================================================
// EVENTS — Sheet: "תקציב"
// Columns: id | name | date | category | budget | spent | done | notes | paidBy
// ============================================================
function getEvents() {
  const sheet = getOrCreateSheet('תקציב');
  const data = sheet.getDataRange().getValues();
  const events = [];

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    if (!row[1]) continue;
    events.push({
      id: row[0] || i,
      name: row[1],
      date: row[2] ? row[2].toString() : '',
      category: row[3] || 'שונות',
      budget: Number(row[4]) || 0,
      spent: Number(row[5]) || 0,
      done: row[6] === true || row[6] === 1 || row[6] === 'TRUE',
      notes: row[7] || '',
      paidBy: row[8] || '',
    });
  }
  return events;
}

function updateEvent(body) {
  const sheet = getOrCreateSheet('תקציב');
  const data = sheet.getDataRange().getValues();

  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == body.id) {
      if (body.spent !== undefined) sheet.getRange(i + 1, 6).setValue(body.spent);
      if (body.done !== undefined)  sheet.getRange(i + 1, 7).setValue(body.done ? 1 : 0);
      if (body.notes !== undefined) sheet.getRange(i + 1, 8).setValue(body.notes);
      if (body.paidBy !== undefined) sheet.getRange(i + 1, 9).setValue(body.paidBy);
      return { success: true };
    }
  }
  return { error: 'Event not found: ' + body.id };
}

function addEvent(body) {
  const sheet = getOrCreateSheet('תקציב');
  const lastRow = sheet.getLastRow();
  const newId = lastRow; // simple auto-increment
  sheet.appendRow([
    newId, body.name, body.date, body.category,
    body.budget, body.spent || 0, 0, body.notes || '', body.paidBy || ''
  ]);
  return { success: true, id: newId };
}

// ============================================================
// CASH — Sheet: "מזומן"
// Columns: id | date | desc | amount | type | paidBy | linkedEventId
// ============================================================
function getCash() {
  const sheet = getOrCreateSheet('מזומן');
  const data = sheet.getDataRange().getValues();
  const entries = [];

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    if (!row[2]) continue;
    entries.push({
      id: row[0] || i,
      date: row[1] ? row[1].toString() : '',
      desc: row[2],
      amount: Number(row[3]) || 0,
      type: row[4] || 'income',
      paidBy: row[5] || '',
      linkedEventId: row[6] || null,
    });
  }
  return entries;
}

function addCashEntry(body) {
  const sheet = getOrCreateSheet('מזומן');
  const newId = sheet.getLastRow();
  sheet.appendRow([
    newId, body.date, body.desc, body.amount,
    body.type, body.paidBy || '', body.linkedEventId || ''
  ]);
  return { success: true, id: newId };
}

function deleteCash(body) {
  const sheet = getOrCreateSheet('מזומן');
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == body.id) {
      sheet.deleteRow(i + 1);
      return { success: true };
    }
  }
  return { error: 'Entry not found' };
}

// ============================================================
// GIFTS — Sheet: "רעיונות"
// Columns: id | icon | name | forWhom | priceRange | tag | notes
// ============================================================
function getGifts() {
  const sheet = getOrCreateSheet('רעיונות');
  const data = sheet.getDataRange().getValues();
  const gifts = [];

  for (let i = 1; i < data.length; i++) {
    const row = data[i];
    if (!row[2]) continue;
    gifts.push({
      id: row[0] || i,
      icon: row[1] || '🎁',
      name: row[2],
      forWhom: row[3] || '',
      priceRange: row[4] || '',
      tag: row[5] || '',
      notes: row[6] || '',
    });
  }
  return gifts;
}

function addGift(body) {
  const sheet = getOrCreateSheet('רעיונות');
  const newId = sheet.getLastRow();
  sheet.appendRow([newId, body.icon, body.name, body.forWhom, body.priceRange, body.tag, body.notes]);
  return { success: true, id: newId };
}

function deleteGift(body) {
  const sheet = getOrCreateSheet('רעיונות');
  const data = sheet.getDataRange().getValues();
  for (let i = 1; i < data.length; i++) {
    if (data[i][0] == body.id) {
      sheet.deleteRow(i + 1);
      return { success: true };
    }
  }
  return { error: 'Gift not found' };
}

// ============================================================
// SETTINGS — Sheet: "הגדרות"
// ============================================================
function getSettings() {
  const sheet = getOrCreateSheet('הגדרות');
  const data = sheet.getDataRange().getValues();
  const settings = {};
  for (let i = 0; i < data.length; i++) {
    if (data[i][0]) settings[data[i][0]] = data[i][1];
  }
  return {
    totalStudents: Number(settings['מספר תלמידים']) || 27,
    feePerStudent: Number(settings['תשלום פר ילד']) || 500,
    carryOver: Number(settings['יתרה משנה שעברה']) || 2020.5,
    year: settings['שנת לימודים'] || 'תשפ״ד-תשפ״ה',
    className: settings['כיתה'] || 'ו׳',
  };
}

// ============================================================
// SETUP — Run once to create sheets and headers
// ============================================================
function setupSheets() {
  createSheetWithHeaders('מזומן', ['id', 'תאריך', 'תיאור', 'סכום', 'סוג', 'שילם/ה', 'ארוע מקושר']);
  createSheetWithHeaders('רעיונות', ['id', 'אמוג׳י', 'שם', 'עבור מי', 'טווח מחיר', 'תג', 'הערות']);
  createSheetWithHeaders('הגדרות', ['מפתח', 'ערך']);

  const settingsSheet = ss.getSheetByName('הגדרות');
  settingsSheet.appendRow(['מספר תלמידים', 27]);
  settingsSheet.appendRow(['תשלום פר ילד', 500]);
  settingsSheet.appendRow(['יתרה משנה שעברה', 2020.5]);
  settingsSheet.appendRow(['שנת לימודים', 'תשפ״ד-תשפ״ה']);
  settingsSheet.appendRow(['כיתה', 'ו׳']);

  Logger.log('✅ Setup complete!');
}

// ============================================================
// HELPERS
// ============================================================
function getOrCreateSheet(name) {
  return ss.getSheetByName(name) || ss.insertSheet(name);
}

function createSheetWithHeaders(name, headers) {
  let sheet = ss.getSheetByName(name);
  if (!sheet) {
    sheet = ss.insertSheet(name);
    sheet.appendRow(headers);
    sheet.getRange(1, 1, 1, headers.length).setFontWeight('bold');
  }
  return sheet;
}

